%[text] # 例5.3（拡大処理）
%[text] 村松正吾　「多次元信号・画像処理の基礎と展開」
%[text] 動作確認： MATLAB R2025b
%[text] ## 準備
isVerbose = false;
prj = matlab.project.currentProject;
prjroot = prj.RootFolder;
datfolder = fullfile(prjroot,"data");
resfolder = fullfile(prjroot,"results");
myfilename = "example05_03"; % mfilename

%imgname = "msipimg02";
imgname = "msipimg07";
imgfmt = "tiff";
%%
%[text] ## 画像データの読込
imgfile = fullfile(datfolder,imgname);
X = imresize(rgb2gray(imread(imgfile,imgfmt)),[96 96]);
%%
%[text] ## 原画像
U = imresize(X,0.5,'box'); % 縮小
figure(1) %[output:002d43ca]
imshow(U) %[output:002d43ca]
title('原画像')  %[output:002d43ca]
%%
%[text] ## 最近傍補間
V = imresize(U,2,'nearest'); % 拡大
figure(2) %[output:37f19ab3]
imshow(V) %[output:37f19ab3]
title('最近傍補間画像')  %[output:37f19ab3]
%%
%[text] ## 双線形補間
Y = imresize(U,2,'bilinear'); % 拡大
figure(3) %[output:6fe3632e]
imshow(Y) %[output:6fe3632e]
title('双線形補間画像')  %[output:6fe3632e]
%%
%[text] ## 結果出力
imwrite(U,fullfile(resfolder,"fig05-03a.png"))
imwrite(V,fullfile(resfolder,"fig05-03b.png"))
imwrite(Y,fullfile(resfolder,"fig05-03c.png"))
%%
